class UserViewModel(private val userRepository: UserRepository) : ViewModel() {

    private val _userState = MutableLiveData<UserState>()
    val userState: LiveData<UserState> = _userState

    private val _users = MutableLiveData<List<User>>()
    val users: LiveData<List<User>> = _users

    fun loadUsers() {
        _userState.value = UserState.Loading
        viewModelScope.launch {
            try {
                val result = userRepository.getUsers()
                _users.value = result
                _userState.value = UserState.Success
            } catch (e: Exception) {
                _userState.value = UserState.Error(e.message)
            }
        }
    }
}

sealed class UserState {
    object Loading : UserState()
    object Success : UserState()
    data class Error(val message: String) : UserState()
}

class UserRepository(
    private val userApi: UserApiService,
    private val userDao: UserDao
) {
    suspend fun getUsers(forceRefresh: Boolean = false): List<User> {
        if (forceRefresh || userDao.getUsers().isEmpty()) {
            try {
                val remoteUsers = userApi.fetchUsers()
                userDao.insertAll(remoteUsers)
                return remoteUsers
            } catch (e: NetworkException) {
                return userDao.getUsers()
            }
        }
        return userDao.getUsers()
    }

    suspend fun getUserById(id: Int): User? {
        return userDao.getUserById(id) ?: userApi.getUser(id)
    }
}

class GetUserProfileUseCase(private val userRepository: UserRepository) {
    suspend operator fun invoke(userId: Int): Result<UserProfile> {
        // Business validation
        if (userId <= 0) {
            return Result.failure(IllegalArgumentException("Invalid user ID"))
        }

        return try {
            val user = userRepository.getUserById(userId)
            if (user != null) {
                Result.success(mapToUserProfile(user))
            } else {
                Result.failure(UserNotFoundException("User not found"))
            }
        } catch (e: Exception) {
            Result.failure(e)
        }
    }

    private fun mapToUserProfile(user: User): UserProfile {
        return UserProfile(
            id = user.id,
            name = user.name,
            email = user.email,
            avatarUrl = user.avatarUrl
        )
    }
}

@Entity(tableName = "users")
data class UserEntity(
    @PrimaryKey val id: Int,
    val name: String,
    val email: String
)

@Dao
interface UserDao {
    @Query("SELECT * FROM users")
    suspend fun getUsers(): List<UserEntity>

    @Query("SELECT * FROM users WHERE id = :id")
    suspend fun getUserById(id: Int): UserEntity?

    @Insert(onConflict = OnConflictStrategy.REPLACE)
    suspend fun insertAll(users: List<UserEntity>)

    @Delete
    suspend fun delete(user: UserEntity)
}

@Database(entities = [UserEntity::class], version = 1)
abstract class AppDatabase : RoomDatabase() {
    abstract fun userDao(): UserDao
}
